insert into public.recipes (id, cat, name, emoji, kcal, p, quick, descr, ingredients, steps, sort) values
  ('idea-oats', 'pdj', 'Overnight oats protéiné', '🥣', 390, 35, true, 'Se prépare la veille, se mange (ou se boit) en voiture.', '["40 g de flocons d''avoine","250 ml de lait d''amande","1 dose de Vegan Protein","une poignée de fruits rouges","1 c. à café de graines de chia"]'::jsonb, '["La veille, mélange flocons + lait + protéine + chia dans un bocal.","Laisse une nuit au frigo.","Le matin, ajoute les fruits."]'::jsonb, 0),
  ('idea-pancakes', 'pdj', 'Pancakes protéinés', '🥞', 400, 35, true, 'Sans huile, à la poêle antiadhésive.', '["40 g de flocons mixés","2 œufs","1 banane écrasée","1/2 dose de Vegan Protein","cannelle"]'::jsonb, '["Mixe le tout en pâte.","Cuis en petits pancakes, poêle antiadhésive sans huile.","Garnis de fruits ou d''un filet de sirop léger."]'::jsonb, 1),
  ('idea-tofuscramble', 'pdj', 'Tofu brouillé express', '🍳', 290, 22, true, 'L''alternative aux œufs, goût brouillé.', '["150 g de tofu ferme","curcuma, paprika, sel kala namak (goût œuf)","1 tranche de pain complet"]'::jsonb, '["Écrase le tofu à la fourchette.","Poêle antiadhésive + épices, 5 min.","Sers avec le pain."]'::jsonb, 2),
  ('idea-skyrmuesli', 'pdj', 'Skyr soja & muesli', '🥣', 320, 20, true, 'Rapide. Choisis un skyr SOJA (plus protéiné que l''amande) et un muesli sans sucre ajouté.', '["150 g de skyr/yaourt soja protéiné","40 g de muesli sans sucre ajouté","fruits frais"]'::jsonb, '["Mélange skyr + muesli.","Ajoute les fruits."]'::jsonb, 3),
  ('idea-buddha', 'dej', 'Buddha bowl tofu', '🥗', 470, 32, true, 'Protéiné, frais, sec en gras.', '["150 g de tofu fumé ou teriyaki","80 g de quinoa (cru) cuit","80 g d''edamame","crudités (carotte, chou, concombre)","sauce soja + citron + gingembre"]'::jsonb, '["Cuis le quinoa.","Poêle le tofu.","Assemble avec edamame et crudités, nappe de sauce."]'::jsonb, 4),
  ('idea-omelette', 'dej', 'Omelette garnie', '🍳', 400, 24, false, 'Rapide et rassasiant.', '["3 œufs","champignons + épinards","1 tranche de pain complet"]'::jsonb, '["Fais revenir champignons et épinards.","Verse les œufs battus, cuis l''omelette.","Sers avec le pain."]'::jsonb, 5),
  ('idea-steak', 'dej', 'Steak végétal & légumes rôtis', '🥩', 450, 30, false, 'Avec HappyVore ou Garden Gourmet.', '["1 steak végétal","grosse portion de légumes rôtis","100 g de patate douce ou lentilles"]'::jsonb, '["Rôtis les légumes au four.","Poêle le steak.","Assemble."]'::jsonb, 6),
  ('idea-wrap', 'dej', 'Wrap protéiné', '🌯', 400, 22, true, 'À emporter, se mange à une main.', '["1 tortilla complète","jambon La Vie ou tofu","crudités","1 c. à soupe de houmous"]'::jsonb, '["Tartine le houmous.","Garnis de protéine + crudités.","Roule serré."]'::jsonb, 7),
  ('idea-medbowl', 'dej', 'Bowl méditerranéen', '🥙', 470, 26, true, 'Pois chiches + œuf, frais et complet.', '["150 g de pois chiches","1 œuf dur","concombre + tomate","60 g de boulgour (cru) cuit","citron, herbes"]'::jsonb, '["Cuis le boulgour.","Assemble pois chiches, œuf, légumes.","Assaisonne citron + herbes."]'::jsonb, 8),
  ('idea-curry', 'diner', 'Curry de pois chiches express', '🍛', 520, 22, false, 'Réconfortant, prêt en 15 min.', '["150 g de pois chiches","150 ml de lait de coco allégé","épinards","tomate concassée + pâte de curry","100 g de riz basmati (cru) cuit"]'::jsonb, '["Fais mijoter tomate + curry + coco.","Ajoute pois chiches et épinards, 10 min.","Sers sur le riz."]'::jsonb, 9),
  ('idea-wok', 'diner', 'Poêlée tofu-légumes & soba', '🍜', 480, 28, false, 'Façon wok, vite fait.', '["150 g de tofu teriyaki","wok de légumes (poivron, brocoli, pousses)","80 g de nouilles soba (crues) cuites","sauce soja"]'::jsonb, '["Cuis les soba.","Saute tofu + légumes au wok.","Mélange, nappe de sauce."]'::jsonb, 10),
  ('idea-galette', 'diner', 'Galette de sarrasin garnie', '🫓', 420, 22, false, 'Œuf + champignons, format crêpe salée.', '["1 galette de sarrasin","1 œuf","champignons","un peu de fromage râpé"]'::jsonb, '["Réchauffe la galette.","Casse l''œuf au centre, ajoute champignons + fromage.","Replie et sers."]'::jsonb, 11),
  ('idea-soupe', 'diner', 'Soupe + œufs durs', '🍲', 350, 18, true, 'Léger, parfait après une grosse journée.', '["gros bol de soupe de légumes maison","2 œufs durs","1 tranche de pain complet"]'::jsonb, '["Réchauffe la soupe.","Sers avec œufs durs + pain."]'::jsonb, 12),
  ('idea-shakefruit', 'snack', 'Shake amande & fruit', '🥤', 330, 31, true, 'Le coup de fouet protéiné.', '["1 dose d''All-in-One ou Vegan Protein","250 ml de lait d''amande","1 banane ou fruits rouges"]'::jsonb, '["Mets tout au shaker ou au blender.","Mixe/secoue."]'::jsonb, 13),
  ('idea-skyrnoix', 'snack', 'Skyr soja & noix', '🥜', 230, 16, true, 'Crémeux + croquant.', '["150 g de skyr/yaourt soja protéiné","une petite poignée de noix","un filet de miel (option)"]'::jsonb, '["Mélange.","Ajoute les noix au moment de manger."]'::jsonb, 14),
  ('idea-houmous', 'snack', 'Houmous & crudités', '🥕', 180, 6, true, 'À grignoter, plein de fibres.', '["2 c. à soupe de houmous","bâtonnets de carotte, concombre, poivron"]'::jsonb, '["Coupe les crudités.","Trempe."]'::jsonb, 15),
  ('idea-houmous-rouge', 'snack', 'Houmous de haricots rouges maison', '🫘', 250, 8, true, 'Ta recette (fait ~4 portions). Riche en bon gras : pour alléger, descends l''huile d''olive à 1 c. à soupe et rallonge à l''eau/aquafaba (~190 kcal/portion).', '["300 g de haricots rouges cuits","3 c. à soupe de tahini","3 c. à soupe d''huile d''olive (1 suffit pour alléger)","1/2 citron pressé","sel, poivre"]'::jsonb, '["Mixe tout jusqu''à consistance lisse.","Ajoute un peu d''eau ou d''aquafaba (jus de la boîte) si trop épais.","Rectifie sel et citron. Sers avec des crudités."]'::jsonb, 16),
  ('idea-clearbarre', 'snack', 'Clear Vegan & barre', '🍫', 270, 32, true, 'Très protéiné, faible en gras.', '["1 dose de Clear Vegan à l''eau glacée","1 barre gourmet vegane Bulk"]'::jsonb, '["Prépare la Clear bien froide.","Accompagne de la barre."]'::jsonb, 17),
  ('idea-porridge', 'pdj', 'Porridge protéiné chaud', '🥣', 400, 35, false, 'Chaud et réconfortant les matins d''hiver.', '["40 g de flocons d''avoine","250 ml de lait d''amande","1 dose de Vegan Protein","1/2 banane en rondelles","cannelle"]'::jsonb, '["Cuis flocons + lait 3-4 min en remuant.","Hors du feu, incorpore la protéine.","Garnis de banane et cannelle."]'::jsonb, 18),
  ('idea-chia', 'pdj', 'Chia pudding amande', '🍮', 300, 20, true, 'Se prépare la veille, ultra rassasiant.', '["30 g de graines de chia","250 ml de lait d''amande","1/2 dose de Vegan Protein","fruits rouges"]'::jsonb, '["Mélange chia + lait + protéine.","Repos une nuit au frigo.","Ajoute les fruits au matin."]'::jsonb, 19),
  ('idea-toastoeuf', 'pdj', 'Toast œuf-avocat', '🥑', 430, 20, true, 'Le brunch express, bon gras maîtrisé.', '["2 tranches de pain complet","1/2 avocat","2 œufs pochés ou au plat","citron, piment"]'::jsonb, '["Toaste le pain, écrase l''avocat dessus.","Cuis les œufs.","Pose-les sur le toast, citron + piment."]'::jsonb, 20),
  ('idea-dahl', 'dej', 'Dahl de lentilles corail', '🍛', 520, 22, false, 'Épicé, réconfortant, peu de gras.', '["80 g de lentilles corail (crues)","150 ml de lait de coco allégé","tomate, oignon, épices (curcuma, cumin)","60 g de riz basmati (cru) cuit"]'::jsonb, '["Fais revenir oignon + épices.","Ajoute lentilles, tomate, coco, mijote 15 min.","Sers sur le riz."]'::jsonb, 21),
  ('idea-poke', 'dej', 'Poke bowl tofu', '🍣', 480, 28, true, 'Frais, façon hawaïen.', '["80 g de riz (cru) cuit","120 g de tofu fumé en dés","edamame","concombre, carotte, oignon rouge","sauce soja + sésame"]'::jsonb, '["Dispose le riz tiède dans un bol.","Ajoute tofu, edamame et crudités.","Nappe de sauce, parsème de sésame."]'::jsonb, 22),
  ('idea-chili', 'dej', 'Chili sin carne', '🫘', 520, 32, false, 'Avec haché végétal et haricots rouges.', '["150 g de haricots rouges","100 g de haché végétal (Garden Gourmet)","tomate concassée, poivron, épices chili","60 g de riz (cru) cuit"]'::jsonb, '["Fais revenir haché + poivron.","Ajoute tomate, haricots, épices, mijote 15 min.","Sers avec le riz."]'::jsonb, 23),
  ('idea-pates', 'diner', 'Pâtes complètes & boulettes La Vie', '🍝', 520, 28, false, 'Le confort food protéiné.', '["80 g de pâtes complètes (crues)","boulettes La Vie","sauce tomate basilic","parmesan végétal (option)"]'::jsonb, '["Cuis les pâtes.","Réchauffe boulettes dans la sauce tomate.","Mélange et sers."]'::jsonb, 24),
  ('idea-shakshuka', 'diner', 'Shakshuka', '🥘', 400, 22, false, 'Œufs pochés dans une sauce tomate-poivron.', '["3 œufs","tomate concassée, poivron, oignon","cumin, paprika","1 tranche de pain complet"]'::jsonb, '["Mijote tomate + poivron + épices.","Casse les œufs dedans, couvre 5-6 min.","Sers avec le pain pour saucer."]'::jsonb, 25),
  ('idea-tofuwok', 'diner', 'Tofu teriyaki & riz sauté légumes', '🍚', 480, 24, false, 'Vite fait au wok.', '["150 g de tofu teriyaki La Vie","80 g de riz (cru) cuit","wok de légumes (poivron, brocoli, petits pois)","sauce soja"]'::jsonb, '["Saute les légumes au wok.","Ajoute le riz cuit et le tofu, fais sauter.","Déglace à la sauce soja."]'::jsonb, 26),
  ('idea-edamame', 'snack', 'Edamame vapeur', '🫛', 190, 17, true, 'Le snack le plus protéiné qui soit.', '["150 g d''edamame (dans la cosse)","sel, ou un peu de piment"]'::jsonb, '["Cuis 5 min à la vapeur ou à l''eau bouillante.","Sale et déguste en pressant les cosses."]'::jsonb, 27),
  ('idea-mugcake', 'snack', 'Mug cake protéiné', '🧁', 220, 28, true, 'Dessert chaud en 1 min au micro-ondes.', '["1 dose de Vegan Protein (chocolat)","1 c. à soupe de cacao","1/2 banane écrasée","1 blanc d''œuf","1/2 c. à café de levure"]'::jsonb, '["Mélange tout dans un mug.","Micro-ondes 1 min.","Laisse tiédir 1 min avant de manger."]'::jsonb, 28),
  ('idea-pommePB', 'snack', 'Pomme & purée de cacahuète', '🍎', 180, 4, true, 'Sucré-salé, croquant.', '["1 pomme en quartiers","1 c. à soupe de purée de cacahuète"]'::jsonb, '["Coupe la pomme.","Trempe dans la purée de cacahuète."]'::jsonb, 29),
  ('idea-orangetofu', 'diner', 'Tofu croustillant à l''orange', '🍊', 480, 26, false, 'Inspirée de The Conscious Plant Kitchen. Croustillant dehors, sauce orange acidulée.', '["200 g de tofu ferme en cubes","1 c. à soupe de maïzena","le jus d''1 orange","2 c. à soupe de sauce soja","1 c. à café de sirop d''érable","ail + gingembre râpés","60 g de riz (cru) cuit"]'::jsonb, '["Presse le tofu, enrobe les cubes de maïzena.","Dore-les à la poêle (peu d''huile) ou à l''airfryer jusqu''à croustillant.","Fais réduire jus d''orange + soja + sirop + ail/gingembre 3 min.","Enrobe le tofu de sauce, sers sur le riz."]'::jsonb, 30),
  ('idea-szechuan', 'diner', 'Tofu Szechuan', '🌶️', 500, 28, false, 'Inspirée de The Conscious Plant Kitchen. Relevé, vite fait au wok.', '["200 g de tofu ferme en cubes","1 poivron + oignon","sauce : soja, vinaigre de riz, ail, piment, pointe de sucre","60 g de riz (cru) cuit"]'::jsonb, '["Dore le tofu jusqu''à croustillant.","Saute poivron + oignon au wok.","Ajoute le tofu et la sauce, fais glacer 2 min.","Sers sur le riz."]'::jsonb, 31),
  ('idea-bolo', 'diner', 'Bolognaise végétale aux lentilles', '🍝', 520, 24, false, 'Inspirée de The Conscious Plant Kitchen. La bolo réconfortante, sans viande.', '["150 g de lentilles vertes cuites","carotte + oignon + céleri hachés","tomate concassée + herbes","80 g de pâtes complètes (crues)"]'::jsonb, '["Fais revenir carotte, oignon, céleri.","Ajoute lentilles, tomate, herbes, mijote 20 min.","Cuis les pâtes, mélange."]'::jsonb, 32),
  ('idea-hpsalad', 'dej', 'Salade vegan hyper-protéinée', '🥗', 450, 35, true, 'Inspirée de The Conscious Plant Kitchen. Le combo edamame + pois chiches + tofu.', '["80 g d''edamame","100 g de pois chiches","80 g de tofu fumé en dés","crudités + graines de courge","sauce tahini + citron + eau"]'::jsonb, '["Assemble edamame, pois chiches, tofu et crudités.","Émulsionne tahini + citron + un peu d''eau.","Nappe, parsème de graines."]'::jsonb, 33),
  ('idea-bbburger', 'dej', 'Burger patate douce & haricots noirs', '🍔', 430, 18, false, 'Inspirée de The Conscious Plant Kitchen. Galette maison moelleuse.', '["1 petite patate douce cuite écrasée","150 g de haricots noirs écrasés","3 c. à soupe de flocons d''avoine","épices (cumin, paprika, ail)","1 pain à burger complet + crudités"]'::jsonb, '["Mélange patate douce, haricots, flocons et épices.","Forme une galette, cuis 5 min par face à la poêle.","Sers dans le pain avec des crudités."]'::jsonb, 34),
  ('idea-teriyaki', 'diner', 'Nouilles teriyaki & edamame', '🍜', 480, 22, false, 'Inspirée de The Conscious Plant Kitchen. Rapide et gourmand.', '["80 g de nouilles (crues) cuites","80 g d''edamame","tofu teriyaki La Vie","légumes (poivron, carotte, oignon vert)","sauce teriyaki (soja, sirop, ail, gingembre)"]'::jsonb, '["Cuis les nouilles.","Saute légumes + tofu, ajoute edamame.","Ajoute nouilles + sauce, fais glacer 2 min."]'::jsonb, 35),
  ('idea-peanutnoodles', 'diner', 'Nouilles crémeuses cacahuète & tofu', '🥜', 540, 26, false, 'Inspirée de The Conscious Plant Kitchen. Sauce satay onctueuse.', '["80 g de nouilles (crues) cuites","120 g de tofu fumé","sauce : purée de cacahuète, soja, citron vert, ail, eau","crudités râpées (carotte, chou)"]'::jsonb, '["Cuis les nouilles.","Dore le tofu.","Mélange nouilles + tofu + sauce cacahuète, parsème de crudités."]'::jsonb, 36),
  ('idea-broccolipasta', 'diner', 'Pâtes crémeuses au brocoli', '🥦', 470, 18, false, 'Inspirée de The Conscious Plant Kitchen. Sauce veloutée sans crème.', '["80 g de pâtes complètes (crues)","1 gros brocoli","ail, levure maltée","un peu de lait d''amande pour lier"]'::jsonb, '["Cuis pâtes + brocoli ensemble.","Mixe une partie du brocoli avec ail, levure maltée et lait d''amande.","Mélange la sauce aux pâtes."]'::jsonb, 37),
  ('idea-enchiladas', 'diner', 'Enchiladas haricots noirs', '🫔', 450, 18, false, 'Inspirée de The Conscious Plant Kitchen. Roulées et gratinées.', '["2 tortillas complètes","150 g de haricots noirs","maïs + poivron","sauce tomate épicée","fromage râpé (option)"]'::jsonb, '["Garnis les tortillas de haricots, maïs, poivron.","Roule-les dans un plat, nappe de sauce tomate.","Gratine 15 min au four."]'::jsonb, 38),
  ('idea-orangecauli', 'diner', 'Chou-fleur croustillant à l''orange', '🍊', 380, 10, false, 'Inspirée de The Conscious Plant Kitchen. La version légumes du tofu à l''orange.', '["1 chou-fleur en bouquets","1 c. à soupe de maïzena","sauce orange (jus d''orange, soja, ail, sirop)","60 g de riz (cru) cuit"]'::jsonb, '["Enrobe le chou-fleur de maïzena, rôtis au four 25 min.","Réduis la sauce orange.","Enrobe et sers sur le riz."]'::jsonb, 39),
  ('idea-oatrolls', 'pdj', 'Petits pains à l''avoine', '🍞', 120, 6, false, 'Inspirée de The Conscious Plant Kitchen. 6 g de protéines, 12 g de fibres, sans œuf. (par petit pain)', '["flocons d''avoine mixés","yaourt soja","levure + sel","graines (option)"]'::jsonb, '["Mélange avoine + yaourt + levure en pâte.","Forme des petits pains.","Cuis 30 min au four à 180°C."]'::jsonb, 40),
  ('idea-bananabars', 'snack', 'Barres avoine, banane & yaourt soja', '🍌', 150, 5, false, 'Inspirée de The Conscious Plant Kitchen. 4 ingrédients, à emporter.', '["2 bananes écrasées","150 g de yaourt soja","120 g de flocons d''avoine","pépites ou fruits secs (option)"]'::jsonb, '["Mélange tout.","Étale dans un moule.","Cuis 30-35 min à 180°C, coupe en barres."]'::jsonb, 41),
  ('idea-kombuchacake', 'snack', 'Gâteau au kombucha (plaisir)', '🍰', 250, 3, false, 'Inspirée de The Conscious Plant Kitchen. 4 ingrédients. Plaisir occasionnel : c''est un gâteau, le kombucha ne sert qu''à lever la pâte. (par part)', '["farine à levée incorporée (ou farine + levure)","sucre","kombucha (saveur fruits rouges ou citron)","huile neutre ou margarine fondue"]'::jsonb, '["Mélange farine + sucre, verse kombucha + huile.","Remue en pâte lisse, verse dans un moule.","Cuis ~50 min à 180°C. Laisse refroidir avant de couper."]'::jsonb, 42),
  ('idea-taboule', 'dej', 'Taboulé sucré-salé tomates & abricots rôtis', '🍅', 400, 14, true, 'Inspirée de Recettes de Julie. Frais et original. J''ai ajouté des pois chiches pour les protéines.', '["60 g de semoule ou boulgour (cru) cuit","tomates + abricots rôtis","100 g de pois chiches","menthe, citron, filet d''huile d''olive"]'::jsonb, '["Cuis la semoule.","Rôtis tomates et abricots 15 min.","Mélange avec pois chiches, menthe et citron."]'::jsonb, 43),
  ('idea-nicecream', 'snack', 'Nicecream banane-kiwi', '🍦', 150, 4, true, 'Inspirée de Recettes de Julie. Glace minute sans sucre ajouté. Une dose de protéine la transforme en dessert protéiné.', '["2 bananes congelées en rondelles","1 kiwi","option : 1/2 dose de Vegan Protein","un filet de lait d''amande"]'::jsonb, '["Mixe bananes congelées + kiwi (+ protéine si tu veux).","Ajoute un peu de lait d''amande pour la texture.","Sers aussitôt."]'::jsonb, 44),
  ('idea-concoyaourt', 'snack', 'Salade concombre au yaourt soja', '🥒', 120, 8, true, 'Inspirée de Recettes de Julie (yaourt soja à la place du grec). Fraîche et protéinée pour quasi rien.', '["1 concombre","150 g de yaourt soja nature","ail, menthe, citron","sel, poivre"]'::jsonb, '["Coupe le concombre.","Mélange yaourt soja + ail + menthe + citron.","Assaisonne et sers bien frais."]'::jsonb, 45),
  ('idea-epeautre', 'dej', 'Salade de petit épeautre', '🌾', 450, 16, false, 'Inspirée de Recettes de Julie. Grains + légumes + fromage ou tofu.', '["70 g de petit épeautre (cru) cuit","tomates cerises, concombre, poivron","feta ou tofu fumé en dés","herbes, citron, filet d''huile d''olive"]'::jsonb, '["Cuis le petit épeautre.","Mélange avec les légumes et le fromage/tofu.","Assaisonne citron + herbes."]'::jsonb, 46),
  ('idea-crepescitron', 'pdj', 'Crêpes citron & graines de pavot', '🍋', 300, 10, false, 'Inspirée de Recettes de Julie. Au lait d''amande.', '["80 g de farine","250 ml de lait d''amande","1 œuf","zeste de citron + graines de pavot"]'::jsonb, '["Mélange farine, lait d''amande, œuf, citron, pavot.","Cuis les crêpes à la poêle.","Garnis léger : fruits ou filet de sirop."]'::jsonb, 47),
  ('idea-pastapestoskyr', 'dej', 'Pâtes pesto au skyr, asperges & brocolis', '🍝', 480, 22, false, 'Inspirée de Recettes de Julie. Le crémeux du pesto sans crème, grâce au skyr soja. Healthy et protéiné.', '["80 g de pâtes (crues) cuites","asperges + brocolis sautés","2 c. à soupe de pesto","150 g de skyr/yaourt soja épais","citron"]'::jsonb, '["Cuis les pâtes, saute asperges et brocolis.","Hors du feu, mélange pesto + skyr soja.","Lie le tout, citron et poivre."]'::jsonb, 48),
  ('idea-oeufscocotte', 'dej', 'Œufs cocotte aux asperges', '🍳', 280, 16, false, 'Inspirée de Recettes de Julie. Au four, protéiné et rapide.', '["2 œufs","asperges vertes","un peu de fromage","sel, poivre"]'::jsonb, '["Dispose asperges + fromage dans un ramequin.","Casse les œufs dessus.","Cuis 12-15 min au four à 180°C."]'::jsonb, 49),
  ('idea-orzopc', 'dej', 'Orzo pesto, asperges & pois chiches', '🍲', 470, 18, false, 'Inspirée de Recettes de Julie. Prêt en 15 min.', '["80 g d''orzo (cru) cuit","100 g de pois chiches","asperges vertes","2 c. à soupe de pesto"]'::jsonb, '["Cuis l''orzo.","Saute asperges + pois chiches.","Mélange avec le pesto."]'::jsonb, 50),
  ('idea-curryasperges', 'diner', 'Curry d''asperges vertes & riz', '🍛', 430, 10, false, 'Inspirée de Recettes de Julie. Vegan, doux au lait de coco. Ajoute du tofu pour les protéines.', '["asperges vertes","150 ml de lait de coco allégé","pâte de curry","60 g de riz (cru) cuit","option : tofu"]'::jsonb, '["Fais revenir la pâte de curry.","Ajoute asperges + coco, mijote 10 min.","Sers sur le riz."]'::jsonb, 51),
  ('idea-quinoafraise', 'dej', 'Salade quinoa, fraises & balsamique', '🍓', 400, 12, false, 'Inspirée de Recettes de Julie. Sucrée-salée, vegan.', '["80 g de quinoa (cru) cuit","fraises","roquette","réduction de balsamique","graines"]'::jsonb, '["Cuis le quinoa, laisse refroidir.","Mélange avec fraises et roquette.","Arrose de balsamique, parsème de graines."]'::jsonb, 52),
  ('idea-coleslaw', 'snack', 'Coleslaw au skyr', '🥗', 150, 8, true, 'Inspirée de Recettes de Julie. Sauce skyr soja au lieu de mayo : léger et protéiné.', '["chou + carotte râpés","150 g de skyr/yaourt soja","moutarde, citron, sel","ciboulette"]'::jsonb, '["Râpe chou et carotte.","Mélange skyr soja + moutarde + citron.","Lie et laisse reposer 10 min."]'::jsonb, 53),
  ('idea-jusvert', 'snack', 'Jus vert concombre-kiwi-gingembre', '🥬', 90, 2, true, 'Inspirée de Recettes de Julie. Rafraîchissant et peu calorique — mais c''est un jus : peu de fibres, zéro protéine. Un plaisir hydratant, pas un repas.', '["1 concombre","1 kiwi","un morceau de gingembre","citron"]'::jsonb, '["Passe le tout à l''extracteur (ou mixe puis filtre).","Sers bien frais."]'::jsonb, 54);
